public class PersonBuilder {
    String name;  // required
    int age;
    PersonBuilder setAge(int a) { age = a; return this; }
    Object build() {
        return name + ", age " + age;   // bug: name may be null
    }
    public static void main(String[] args) {
        System.out.println(new PersonBuilder().setAge(30).build());
    }
